import os
import json
import re
from kafka import KafkaProducer
from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Secure configuration
ALLOWED_TOPICS = set(os.environ.get('ALLOWED_TOPICS', '').split(','))
KAFKA_BOOTSTRAP_SERVERS = os.environ.get('KAFKA_BOOTSTRAP_SERVERS', 'localhost:9092')
KAFKA_SECURITY_PROTOCOL = os.environ.get('KAFKA_SECURITY_PROTOCOL', 'SASL_SSL')
KAFKA_SASL_MECHANISM = os.environ.get('KAFKA_SASL_MECHANISM', 'PLAIN')
KAFKA_SASL_USERNAME = os.environ.get('KAFKA_SASL_USERNAME')
KAFKA_SASL_PASSWORD = os.environ.get('KAFKA_SASL_PASSWORD')
KAFKA_SSL_CAFILE = os.environ.get('KAFKA_SSL_CAFILE')
API_KEY_HEADER = 'X-API-Key'
VALID_API_KEYS = set(os.environ.get('VALID_API_KEYS', '').split(','))

# Topic name validation pattern (alphanumeric, hyphens, underscores, dots)
TOPIC_NAME_PATTERN = re.compile(r'^[a-zA-Z0-9._-]{1,249}$')

# Initialize Kafka producer with security settings
producer_config = {
    'bootstrap_servers': KAFKA_BOOTSTRAP_SERVERS.split(','),
    'value_serializer': lambda v: json.dumps(v).encode('utf-8'),
    'acks': 'all',
    'retries': 3,
    'max_in_flight_requests_per_connection': 1
}

# Add security configuration if credentials are provided
if KAFKA_SASL_USERNAME and KAFKA_SASL_PASSWORD:
    producer_config.update({
        'security_protocol': KAFKA_SECURITY_PROTOCOL,
        'sasl_mechanism': KAFKA_SASL_MECHANISM,
        'sasl_plain_username': KAFKA_SASL_USERNAME,
        'sasl_plain_password': KAFKA_SASL_PASSWORD
    })
    if KAFKA_SSL_CAFILE:
        producer_config['ssl_cafile'] = KAFKA_SSL_CAFILE

producer = KafkaProducer(**producer_config)


def require_api_key(f):
    """Decorator to enforce API key authentication"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get(API_KEY_HEADER)
        if not api_key or api_key not in VALID_API_KEYS:
            return jsonify({'error': 'Unauthorized: Invalid or missing API key'}), 401
        return f(*args, **kwargs)
    return decorated_function


def validate_topic_name(topic_name):
    """Validate topic name against security rules"""
    if not topic_name:
        return False, "Topic name cannot be empty"
    
    if not TOPIC_NAME_PATTERN.match(topic_name):
        return False, "Topic name contains invalid characters or exceeds length limit"
    
    if topic_name not in ALLOWED_TOPICS:
        return False, f"Topic '{topic_name}' is not in the allowlist"
    
    return True, None


def validate_message(message):
    """Validate message content"""
    if not message:
        return False, "Message cannot be empty"
    
    if not isinstance(message, dict):
        return False, "Message must be a JSON object"
    
    # Limit message size (e.g., 1MB)
    message_size = len(json.dumps(message).encode('utf-8'))
    if message_size > 1048576:
        return False, "Message size exceeds 1MB limit"
    
    return True, None


@app.route('/publish', methods=['POST'])
@require_api_key
def publish_message():
    """Securely publish messages to Kafka topics"""
    try:
        # Get topic from request parameters
        topic_name = request.args.get('topic') or request.json.get('topic')
        
        # Validate topic name
        is_valid, error_msg = validate_topic_name(topic_name)
        if not is_valid:
            return jsonify({'error': error_msg}), 400
        
        # Get message from request body
        message = request.json.get('message')
        
        # Validate message
        is_valid, error_msg = validate_message(message)
        if not is_valid:
            return jsonify({'error': error_msg}), 400
        
        # Optional: Get message key for partitioning (also validate)
        message_key = request.json.get('key')
        if message_key:
            if not isinstance(message_key, str) or len(message_key) > 1024:
                return jsonify({'error': 'Invalid message key'}), 400
            message_key = message_key.encode('utf-8')
        
        # Publish message to validated topic
        future = producer.send(topic_name, value=message, key=message_key)
        
        # Wait for confirmation (with timeout)
        record_metadata = future.get(timeout=10)
        
        return jsonify({
            'status': 'success',
            'topic': record_metadata.topic,
            'partition': record_metadata.partition,
            'offset': record_metadata.offset
        }), 200
        
    except Exception as e:
        # Log error without exposing sensitive details
        app.logger.error(f"Error publishing message: {type(e).__name__}")
        return jsonify({'error': 'Failed to publish message'}), 500


@app.route('/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    return jsonify({'status': 'healthy'}), 200


if __name__ == '__main__':
    # Validate configuration on startup
    if not ALLOWED_TOPICS or '' in ALLOWED_TOPICS:
        raise ValueError("ALLOWED_TOPICS environment variable must be set")
    
    if not VALID_API_KEYS or '' in VALID_API_KEYS:
        raise ValueError("VALID_API_KEYS environment variable must be set")
    
    # Run with production WSGI server in production
    app.run(host='127.0.0.1', port=5000, debug=False)